  private cartItems = signal<any[]>([]);

  cart = this.cartItems.asReadonly();

  totalPrice = computed(() =>
    this.cartItems().reduce(
      (sum, item) => sum + item.price,
      0
    )
  );

  addToCart(item: any) {
    this.cartItems.update(
      current => [...current, item]
    );
  }

  clearCart() {
    this.cartItems.set([]);
  }
